import{bQ as t,aL as e,u as r,G as o}from"./chunks/framework.jc7iVf2j.js";const s=JSON.parse('{"title":"你好，认识一下！","description":"关于技术、人文与表达习惯的一点自我介绍。","frontmatter":{"title":"你好，认识一下！","description":"关于技术、人文与表达习惯的一点自我介绍。","date":"2026-03-19T00:00:00.000Z","tags":["必读","知识管理","价值观","技术","人文"],"categories":["社会学人"],"top":true,"copyright":true,"references":[{"title":"How Much Information? 2009 Report on American Consumers（加州大学圣地亚哥分校，日均 34 GB 信息）","url":"https://qi.ucsd.edu/news-article.php?id=1630"},{"title":"索菲·金塞拉《购物狂的异想世界》","url":"https://book.douban.com/subject/2229048/"}],"cover":"/images/cover/self-introduction-cover.png","head":[["link",{"rel":"canonical","href":"https://blog.f0.nz/posts/你好，认识一下！"}]]},"headers":[],"relativePath":"posts/你好，认识一下！.md","filePath":"posts/你好，认识一下！.md","lastUpdated":1780731368000}');const a=t({name:"posts/你好，认识一下！.md"},[["render",function(t,s,a,n,i,p){return e(),r("div",null,[...s[0]||(s[0]=[o('<p>欢迎来到京华/Jhub！这是一个面向雄心勃勃的知识工作者的博客，阅读我的博客需基于以下共识：[[简中互联网七诫]]。——本博客的主旨一，扩大七诫共识。<br> 人类社会的发展基于知识的代际传承，21世纪的人们可以享受人类五千年文明的全部智慧成果。同时，每一个人既是知识的消费者，也是知识的生产者。——本博客的主旨二，让知识流动。<br> 而在信息爆炸的时代，根据研究，每个人每天接收 34 GB 到 74 GB 甚至更高的信息量。我们每个人都面对信息过载的真实恐惧。——本博客的主旨三，重新找回注意力。</p><hr><p>读书使人充实，写作使人精确。我正处于从“大量输入”到“适量输入，适量输出”的转型期。<br> 我现在正处于多种输出形式的混合：当知乎博主写文章和回答、自建私域和博客进行广播、加入高质量社群进行分享等。<br> 加速主义和工业党盛行的当代，盲目的工具崇拜成为趋势。技术上升，人文下降。我希望我能够为各技术社群带来一些人文气，为人和工具厘清界限。<br> 人是拿来爱的，工具是拿来用的。这世界一团糟，是因为工具被拿来爱了，而人却被拿来用了。——索菲·金塞拉《购物狂的异想世界》</p><hr><p>如果你想要加入我的社群，欢迎投递我的邮箱（ <a href="mailto:JT@f0.nz" target="_blank" rel="noreferrer">JT@f0.nz</a>）并表明来意。</p>',5)])])}]]);export{s as __pageData,a as default};
